1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const LOYALTY_THRESHOLD = 2;
4	const LOYALTY_DISCOUNT = 0.2;
5	const FOLLOWUP_DISCOUNT = 0.15;
6	
7	interface Item {
8	  type: string;
9	  material?: string;
10	  enchantment?: number;
11	  cursed?: boolean;
12	}
13	
14	interface QuoteStep {
15	  op: "quote";
16	  items: Item[];
17	}
18	
19	interface Damage {
20	  itemType: string;
21	  amount: number;
22	}
23	
24	interface ClaimStep {
25	  op: "claim";
26	  policy: number;
27	  incident: { cause: string; damages: Damage[] };
28	}
29	
30	type Step = QuoteStep | ClaimStep;
31	
32	interface Customer {
33	  yearsWithMHPCO: number;
34	}
35	
36	interface Scenario {
37	  customer: Customer;
38	  steps: Step[];
39	}
40	
41	interface QuoteResult {
42	  premium: number;
43	}
44	
45	interface ClaimResult {
46	  payout: number;
47	  remainingCap: number;
48	}
49	
50	type StepResult = QuoteResult | ClaimResult;
51	
52	const COMPONENT_BASE_PREMIUM = 25;
53	const COMPONENT_INSURANCE_VALUE = 250;
54	const DEDUCTIBLE = 100;
55	const CAP_MULTIPLIER = 2;
56	
57	const BASE_PREMIUMS: Record<string, number> = {
58	  sword: 100,
59	  amulet: 60,
60	  staff: 80,
61	  potion: 40,
62	  rune: COMPONENT_BASE_PREMIUM,
63	  moonstone: COMPONENT_BASE_PREMIUM,
64	};
65	
66	const INSURANCE_VALUES: Record<string, number> = {
67	  sword: 1000,
68	  amulet: 600,
69	  staff: 800,
70	  potion: 400,
71	  rune: COMPONENT_INSURANCE_VALUE,
72	  moonstone: COMPONENT_INSURANCE_VALUE,
73	};
74	
75	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
76	const BLOCK_SIZE = 3;
77	const BLOCK_PREMIUM = 60;
78	
79	const formsBlock = (type: string, count: number): boolean =>
80	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
81	
82	const typeBasePremium = (type: string, count: number): number => {
83	  if (formsBlock(type, count)) return BLOCK_PREMIUM;
84	  return count * BASE_PREMIUMS[type];
85	};
86	
87	const countByType = (items: Item[]): Map<string, number> =>
88	  items.reduce(
89	    (counts, item) =>
90	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
91	    new Map<string, number>(),
92	  );
93	
94	const policyBasePremium = (items: Item[]): number =>
95	  [...countByType(items)].reduce(
96	    (base, [type, count]) => base + typeBasePremium(type, count),
97	    0,
98	  );
99	
100	// A rate rule contributes its rate to a subject only when it applies.
101	interface RateRule<T> {
102	  applies: (subject: T) => boolean;
103	  rate: number;
104	}
105	
106	const sumApplicableRates = <T>(rules: RateRule<T>[], subject: T): number =>
107	  rules.reduce(
108	    (rate, rule) => (rule.applies(subject) ? rate + rule.rate : rate),
109	    0,
110	  );
111	
112	const CURSE_SURCHARGE = 0.5;
113	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
114	const HIGH_ENCHANTMENT_THRESHOLD = 5;
115	
116	const SURCHARGE_RULES: RateRule<Item>[] = [
117	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
118	  {
119	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
120	    rate: HIGH_ENCHANTMENT_SURCHARGE,
121	  },
122	];
123	
124	const itemSurcharge = (item: Item): number =>
125	  sumApplicableRates(SURCHARGE_RULES, item) * BASE_PREMIUMS[item.type];
126	
127	const itemSurcharges = (items: Item[]): number =>
128	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
129	
130	interface PolicyContext {
131	  customer: Customer;
132	  isFollowUp: boolean;
133	}
134	
135	// Policy-wide modifiers each apply a signed rate to the policy base:
136	// positive rates are surcharges, negative rates are discounts.
137	const POLICY_MODIFIER_RULES: RateRule<PolicyContext>[] = [
138	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
139	  {
140	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD,
141	    rate: -LOYALTY_DISCOUNT,
142	  },
143	  { applies: ({ isFollowUp }) => isFollowUp, rate: -FOLLOWUP_DISCOUNT },
144	];
145	
146	const policyModifierRate = (context: PolicyContext): number =>
147	  sumApplicableRates(POLICY_MODIFIER_RULES, context);
148	
149	// A signed modifier rate scales a base: positive rates surcharge, negative discount.
150	const applyModifierRate = (base: number, rate: number): number =>
151	  base * (1 + rate);
152	
153	// Strips floating-point error that could nudge an exact value over an
154	// integer boundary, so the rounding below acts on the intended amount.
155	const cleanFloatNoise = (amount: number): number => Number(amount.toFixed(6));
156	
157	// Premiums round up, payouts round down — both in the MHPCO's favor.
158	const roundUpPremium = (amount: number): number =>
159	  Math.ceil(cleanFloatNoise(amount));
160	
161	const roundDownPayout = (amount: number): number =>
162	  Math.floor(cleanFloatNoise(amount));
163	
164	const quotePremium = (items: Item[], context: PolicyContext): number => {
165	  const policyBase = policyBasePremium(items);
166	  const modifierRate = policyModifierRate(context);
167	  // Policy modifiers scale the policy base only; item surcharges are added
168	  // separately (outside the modifier scope), then the flat fee comes last.
169	  const modifiedPolicyBase = applyModifierRate(policyBase, modifierRate);
170	  const total = modifiedPolicyBase + itemSurcharges(items) + PROCESSING_FEE;
171	  return roundUpPremium(total);
172	};
173	
174	const insuranceSum = (items: Item[]): number =>
175	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
176	
177	// A policy's payout cap is twice its total insured value.
178	const policyCap = (items: Item[]): number =>
179	  CAP_MULTIPLIER * insuranceSum(items);
180	
181	interface Policy {
182	  items: Item[];
183	  remainingCap: number;
184	}
185	
186	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
187	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
188	
189	const qualifiesForHalfReimbursement = (item: Item): boolean =>
190	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
191	
192	// The spec names two reimbursement clauses. The high-enchantment clause
193	// (enchantment >= 8) reimburses 50%; the dragon-material clause reimburses
194	// 100%. When both apply, 50% wins — the lower payout. Since 100% reimbursement
195	// is identical to the default (full) reimbursement, the dragon clause needs no
196	// branch of its own: it changes nothing the default doesn't already do, and the
197	// "50% wins" interaction falls out naturally from preferring the half clause
198	// here. A dedicated dragon branch would be a no-op the tests can't distinguish.
199	const reimbursement = (item: Item, amount: number): number =>
200	  qualifiesForHalfReimbursement(item)
201	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE * amount
202	    : amount;
203	
204	// The damaged item is the policy item whose type the damage names. Today every
205	// damage references an insured type, so the lookup always succeeds; the upcoming
206	// "claim references item not in policy" test will give this its own failure path.
207	const insuredItemFor = (damage: Damage, policy: Policy): Item =>
208	  policy.items.find((item) => item.type === damage.itemType)!;
209	
210	const damagePayout = (damage: Damage, policy: Policy): number =>
211	  reimbursement(insuredItemFor(damage, policy), damage.amount) - DEDUCTIBLE;
212	
213	// Each damage carries its own deductible, so the requested payout is the sum
214	// of per-damage payouts — not the deductible applied once to the total.
215	const requestedPayout = (step: ClaimStep, policy: Policy): number =>
216	  step.incident.damages.reduce(
217	    (sum, damage) => sum + damagePayout(damage, policy),
218	    0,
219	  );
220	
221	const settleClaim = (step: ClaimStep, policy: Policy): ClaimResult => {
222	  const payout = Math.min(
223	    roundDownPayout(requestedPayout(step, policy)),
224	    policy.remainingCap,
225	  );
226	  policy.remainingCap -= payout;
227	  return { payout, remainingCap: policy.remainingCap };
228	};
229	
230	// Steps are processed in order against accumulating state: each quote
231	// registers a policy (keyed by its step index) and marks that a prior
232	// quote exists, so later quotes count as follow-ups; each claim settles
233	// against an already-registered policy. The sequential state-building is
234	// why this is an explicit loop rather than a (pure) map.
235	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
236	  const policies = new Map<number, Policy>();
237	  let hasPriorQuote = false;
238	  const results: StepResult[] = [];
239	
240	  scenario.steps.forEach((step, index) => {
241	    if (step.op === "claim") {
242	      const policy = policies.get(step.policy)!;
243	      results.push(settleClaim(step, policy));
244	      return;
245	    }
246	    const context: PolicyContext = {
247	      customer: scenario.customer,
248	      isFollowUp: hasPriorQuote,
249	    };
250	    hasPriorQuote = true;
251	    policies.set(index, {
252	      items: step.items,
253	      remainingCap: policyCap(step.items),
254	    });
255	    results.push({ premium: quotePremium(step.items, context) });
256	  });
257	
258	  return { results };
259	};
